import { useState, useEffect } from "react";
import KPICards from "./components/KPICards";
import DailyChart from "./components/DailyChart";
import MediaTable from "./components/MediaTable";
import Sidebar from "./components/Sidebar";
import Header from "./components/Header";

const API = "http://localhost:3001";

export default function App() {
  const [daily, setDaily] = useState([]);
  const [total, setTotal] = useState(null);
  const [media, setMedia] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchAll = async () => {
      try {
        const [dailyRes, totalRes, mediaRes] = await Promise.all([
          fetch(`${API}/insights/daily`),
          fetch(`${API}/insights/total`),
          fetch(`${API}/media`),
        ]);

        const [dailyData, totalData, mediaData] = await Promise.all([
          dailyRes.json(),
          totalRes.json(),
          mediaRes.json(),
        ]);

        // 🔥 GARANTIR ARRAY
        const safeDaily = Array.isArray(dailyData)
          ? dailyData
          : dailyData?.data || [];

        const safeMedia = Array.isArray(mediaData)
          ? mediaData
          : mediaData?.data || [];

        setDaily(safeDaily);
        setTotal(totalData);
        setMedia(safeMedia);

      } catch (err) {
        console.error("Erro:", err);
      } finally {
        setLoading(false);
      }
    };

    fetchAll();
  }, []);

  // ==========================
  // 🔢 KPIs
  // ==========================
  const formattedTotal = {
    followers: total?.followers_count ?? 0,
    profile_views: total?.profile_views ?? 0,
    reach: Array.isArray(daily) && daily.length > 0
      ? daily[daily.length - 1].reach
      : 0,
    impressions: 0,
  };

  // ==========================
  // 📈 CHART DATA
  // ==========================
  const chartData = Array.isArray(daily)
    ? daily.map((d) => ({
        ...d,
        followers_count: total?.followers_count ?? 0,
      }))
    : [];

  return (
    <div className="flex bg-[#0a0a0f] text-white min-h-screen">
      <Sidebar />

      <main className="flex-1">
        <Header />

        <div className="p-8 space-y-8">
          <KPICards data={formattedTotal} loading={loading} />

          <DailyChart data={chartData} loading={loading} />

          <MediaTable data={media} loading={loading} />
        </div>
      </main>
    </div>
  );
}
